function [logTtl,logDat,infTtl,infDat] = fTrexLogReadV02(day,scnDir,scan)%% read and return logdata for TREX experiments% [logTtl,logDat,infTtl,infDat] = fTrexLogReadV02(day,scnDir,scan)% day: day% scnDir: scan directory% scan: scan number% logTtl: logfile title% logDat: logfile data% infTtl: information title% infDat: information data%% Written by Kei Nakamura% Created on Friday, November 10th 2006.% Modified on Monday, June 1st 2009%% main body[adr logNam] = vrnLFNV01(scan);     % log name, 1:log 2:inf 3:vrn 4:spt if day<6        % first phase of data system    logDat = textread([scnDir,'/',logNam{1}]);    [infTtl,infDat,logTtl] = vrnInfRead2([scnDir,'/',logNam{2}]);elseif day<23   % before we change some format    [logTtl,logDat] = fLogReadV01([scnDir,'/',logNam{1}]);    [infTtl,infDat] = vrnInfRead([scnDir,'/',logNam{2}]);elseif day==46&&scan==40    [logTtl,logDat] = fLogReadV01([scnDir,'/',logNam{1}]);    [infTtl,infDat] = vrnInfRead([scnDir,'/',logNam{2}]);elseif day>=142&&day<=143 %staging no info    [logTtl,logDat] = fLogReadV03([scnDir,'/',logNam{1}]);    infTtl = 0; infDat = 0;elseif day>=146&&day<=149 %staging no info    [logTtl,logDat] = fLogReadV03([scnDir,'/',logNam{1}]);    infTtl = 0; infDat = 0;elseif day==1000    logNam{1} = ['k',logNam{1}];    [logTtl,logDat] = fLogReadV03([scnDir,'/',logNam{1}]);    infTtl = 0; infDat = 0;elseif day==1001    logNam{1} = ['M',logNam{1}];    [logTtl,logDat] = fLogReadV01([scnDir,'/',logNam{1}]);    infTtl = 0; infDat = 0;else            % current way    [logTtl,logDat] = fLogReadV02([scnDir,'/',logNam{1}]);    [infTtl,infDat] = vrnInfRead([scnDir,'/',logNam{2}]);end
